var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제5 방위선, 거점 기지","JPN":"人類統合防衛軍第5防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 5th Defense Line","TWN":"人類共同保衛軍第五防線基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"5방위선 담당관님. 델타 세븐 사령관, 카린 웡 소령입니다.","JPN":"第5防衛線の担当官殿。デルタセブン司令官カリン・ウォン少佐です。","ENG":"You must be the 5th Line's Officer. I am the commander of Delta Seven, Major Karin Wong.","TWN":"你好，第五道防線的負責人。我是第七三角洲部隊司令官，卡琳少校。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사전에 전달받으셨겠지만, 저희는 지금 아포리아의 토벌을 위한 단서를 찾고 있습니다.","JPN":"事前伝達があったと思いますが、私たちは現在アポリア討伐に向けて手がかりを探している最中です。","ENG":"As you have already been notified, we are currently looking for clues to defeat Aporia.","TWN":"你應該有收到通知，我們正為了討伐阿波利亞尋找線索。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"인류 초유의 비상사태입니다. 부디 협조 부탁드리겠습니다.","JPN":"人類史上前例の無い非常事態です。どうかご協力をお願いします。","ENG":"Humankind is in an unprecedented state of emergency. We appreciate your cooperation.","TWN":"現在是人類史無前例的緊急時刻。請你一定要協助我們。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"협조? 젠장, 다들 뭐하다 이렇게 늦은 거야?","JPN":"協力だと？　くそっ、あんたら今まで何をしてた？","ENG":"Cooperation? Dammit. What took you so long to get here anyway?","TWN":"協助？可惡，你們幹什麼吃的，這麼晚才來？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"니들이 크로스로드의 영웅이면 다야? 1지구만 아니면 다른 방위선은 뚫려도 상관없다는 거지?","JPN":"何がクロスロードの英雄だ。第1地区以外なら防衛線が突破されても構わないと思ってるんだろ？","ENG":"So you're the heroes of Crossroads, is that it?! You don't care if other Defense Lines fall as long as it's not District 1, do you?!","TWN":"十字路口的英雄就了不起嗎？只要第一區沒事，其他防線被攻破也沒有關係嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"뭐야, 용케 아직도 안 도망치고 있었냐? 제이콥?","JPN":"何だ、とっくに逃げたと思っていたんだけどな、ジェイコブ？","ENG":"What? Jacob, why haven't you run away yet?","TWN":"什麼，是你？雅各？你居然還沒有逃跑？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"너 뭐야? 로널드? 너는 왜 거기 끼어 있어?","JPN":"あ？　ロナルドか？　何でその輪の中に入っているんだ？","ENG":"Who's that? Ronald? What are you doing over there?","TWN":"你誰啊？羅那魯多·李？你怎麼在這裡？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"연구비 부족하다면서 징징거리던 찌질이 자식이 꽤나 출세했는데?","JPN":"研究費が足りないって泣きべそかいてた奴が、ずいぶん出世したみたいだな？","ENG":"You appear to be doing well for a crybaby prick who always whined about not getting enough grant money for your research, eh?","TWN":"整天抱怨研究費不夠，你這沒出息的小子總算出頭天啦？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"흥, 네 눈에는 아직도 내가 네 직원처럼 보이나 봐? 사업도 말아먹은 주제에?","JPN":"ふん、まだ僕のことをお前の部下だと思っているのか？　会社も守れなかったくせに！","ENG":"Hmph. Do you still think I work for you? You're the one who burned down your whole business!","TWN":"哼，我現在可不是你的員工，而且你的事業不是早就搞砸了嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"지금은 너나 나나 이젠 연금도 못 받는 말단 공무원 신세라고!","JPN":"もう僕もお前も、年金すら受給できないただの末端公務員なんだよ！","ENG":"Now, you and I are no different. We're lowly civil servants who can't even receive any pensions!","TWN":"現在你和我一樣，都只是連退休金都拿不到的基層公務員！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"하! 내가 망하고 싶어서 망했냐? 네피림 사태가 터져서 망한 거 아니야!","JPN":"ふん！　会社が倒産したのは俺のせいじゃねえよ！　ネフィリムのせいだろう！","ENG":"Ha! You think I wanted to close shop? It was taken away from me because of the Nephil incident!","TWN":"哈！是我想搞砸的嗎？還不是被諾菲力事件連累的！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 이거 곤란하게 됐네요.","JPN":"ハハ、これは困りましたね。","ENG":"Hah hah, this doesn't look good.","TWN":"哈哈，真是麻煩。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 여러분? 여러분이 어떤 관계인지는 모르겠지만, 사이 좋게 지내보는 건 어때요?","JPN":"さあ、お二人とも？　お二人の関係性はよくわかりませんが、仲良くするのはどうでしょうかね？","ENG":"Okay, everyone? I don't know what past relationship y'all had, but can't we all just get along?","TWN":"好了，各位？雖然不清楚大家是什麼關係，但我們還是要好好相處才對？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어차피 아포리아를 쓰러트리지 못하면, 사이좋게 손잡고 황천길 건너게 될 사이잖아요.","JPN":"どうせアポリアを倒せなかったら、一緒に仲良くあの世行きなんですよ。","ENG":"I mean, if we don't defeat Aporia, won't we all be pushing daisies together?","TWN":"這樣就算打不倒阿波利亞，至少還有人可以一起共赴黃泉嘛。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"맞습니다. 아포리아 토벌 작전에는 세계의 운명이 달려있어요.","JPN":"シノンさんの言うとおりです。アポリア討伐作戦には世界の命運がかかっています。","ENG":"She's right. The fate of the world rests on this operation to eliminate Aporia.","TWN":"二位，討伐阿波利亞的作戰關係到這個世界的命運。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니 사사로운 감정은 잠시 접어두시고, 부디 저희에게 협조 부탁드리겠습니다.","JPN":"ですから些細な感情は一旦しまっておいて、どうか私たちに協力してください。","ENG":"So, please put personal feelings aside for now and cooperate with us.","TWN":"所以，請暫時先放下私人恩怨，務必協助我們。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"제기랄, 그딴 건 이미 알고 있다고!","JPN":"くそっ、そんなのわかってるよ！","ENG":"Dammit, I already know that!","TWN":"該死，那些我也知道！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"따라와. 안 그래도 보여주고 싶은 게 있었으니까.","JPN":"ついてこい、ちょうど見せたいものがあるんだ。","ENG":"Follow me. I have something I wanted to show you anyway.","TWN":"跟著我，正好有東西要給你們看。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"망할, 특수탄이 다 떨어졌군.","JPN":"くそ、特殊弾が底を突いたか。","ENG":"Crud! I'm outta special bullets.","TWN":"糟糕，特殊彈都用光了。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"부상자 이송을 서둘러! 고치 관측소까지 퇴각한다!","JPN":"負傷者の移送を急げ！　繭観測所まで退却する！","ENG":"Hurry up moving the injured! We retreat to the cocoon observatory!","TWN":"盡快移送傷患！撤退至繭觀測站！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"대, 대장님! 목표가 빠른 속도로 접근하고 있습니다.","JPN":"た、隊長！　ターゲットが猛スピードで接近してきています。","ENG":"C-captain! The target is approaching us fast.","TWN":"隊，隊長！目標正在快速靠近中。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"방향은 남동쪽! 거리 400……! 350……! 320……!","JPN":"南東方向！　距離400……！　350……！　320……！","ENG":"Direction is southeast! Distance is 400...! 350...! 320...!","TWN":"東南方向！距離400……！350……！320……！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이건, 어딘가의 교전 영상이로군요.","JPN":"これは、どこかの交戦映像ですね。","ENG":"This seems to be a video of some skirmish.","TWN":"這個是？某個地方的小規模交戰影片。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"근데 갑자기 이런 걸 왜 보여주시는 거죠?","JPN":"なぜこれを私たちに？","ENG":"But why are you showing this to us?","TWN":"喔？你為什麼突然給我們看這個？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"영웅들이라고 하더니만, 생각보다 눈치들이 없군.","JPN":"英雄だと聞いていたのに、察しが悪いな。","ENG":"For those who are called heroes, you're slow to notice what's happened.","TWN":"哼哼，還十字路口的英雄呢，一點觀察力都沒有。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"잘 봐, 이건 제6 방위선에서 전사한 방위군 병사의 바디캠이라고.","JPN":"よく見ろ、これは第6防衛線で戦死した防衛軍兵士のボディカメラだ。","ENG":"Look. This is the bodycam of a fallen soldier at the 6th Defense Line.","TWN":"看清楚，這是在第六防線中戰死的保衛軍士兵的穿戴式攝影機。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"바디캠? 잘도 이렇게 멀쩡한 걸 구했네.","JPN":"ボディカメラ？　よくこんなに保存状態の良い物を見つけたな。","ENG":"Bodycam? I'm surprised you were even able to obtain this footage.","TWN":"穿戴式攝影機？居然能弄到這麼厲害的玩意兒。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"시끄러워, 사업하는 사람은 정보가 빨라야 살아남는 거야.","JPN":"うるさい、ビジネスマンにとって情報収集の速さは命なんだ。","ENG":"Shut it. Businessmen need to be quick when it comes to information in order to survive.","TWN":"閉嘴，做生意的人只有消息靈通才能活下來。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"아무튼 중요한 건 여기가 아니야. 조금 더 뒤로 넘기지.","JPN":"とにかく大事な場面はここじゃない。もう少し先送りしよう。","ENG":"Anyway, this isn't the important part. I'll fast forward it a little.","TWN":"不過這不是重點，接著再往下看。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"하아……! 하아……! 하아……!","JPN":"はぁ……！　はぁ……！　はぁ……！","ENG":"*Huff*...! *Huff*...! *Huff*...!","TWN":"哈啊……！哈啊……！哈啊……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이런 제기랄!","JPN":"クソ！","ENG":"Dammit!","TWN":"該死！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"오지 마……! 오지 말라고 이 괴물아!!","JPN":"来るな……！　こっちに来るな、化け物め！！","ENG":"Get away...! Get away from me, you monster!!","TWN":"別過來……！你這個怪物！別過來！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아아아!","JPN":"うわぁああ！","ENG":"AAAARGH!","TWN":"呃啊啊啊啊！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"으윽……!","JPN":"ううっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>...</color>","TWN":"<color=#ff3636>……</color>"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐, 고치로 다가가고 있잖아?","JPN":"待って、繭の方に近づいている？","ENG":"Wait, it's headed toward the cocoon?","TWN":"等一下，他靠近繭做什麼？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"무슨…… 지금 무슨 짓을 하려는 거지?","JPN":"何を……今何をしようとしているんだろう？","ENG":"What...? What's it trying to do?","TWN":"什麼……這是在？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"자, 다들 똑똑히 보라고. 내가 말했던 부분이 여기니까.","JPN":"さぁ、全員しっかり見ておけよ。見てもらいたいのはここだ。","ENG":"Okay, keep your eyes peeled. This is what I just said.","TWN":"來，大家都仔細看清楚了，我要說的就是這個。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아포리아가……!","JPN":"アポリアが……！","ENG":"Aporia's...!","TWN":"阿波利亞在……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"고치를 찢고, 네피림의 유체를 강제로 끌어내고 있어……?","JPN":"繭を引き裂いて、ネフィリムの幼体を無理やり引きずり出している……？","ENG":"It's ripping the cocoon and pulling out the Nephil larva...?","TWN":"他在撕破繭，強行拽出諾菲力的幼體……？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"로널드 박사님, 저건 대체?","JPN":"ロナルド博士、これはいったい？","ENG":"Dr. Ronald, what are we looking at?","TWN":"博士，這到底？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"유체에서 핵을 꺼내 흡수하고 있어.","JPN":"幼体から核を取り出して吸収しているんだ。","ENG":"It's taking out the larva's core and absorbing it.","TWN":"他掏出了幼體的核心，正在吸收他。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"핵을 흡수하고 있다고요?","JPN":"核を吸収するですって？","ENG":"Absorbing the core?","TWN":"吸收核心嗎？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐.","JPN":"そういえば。","ENG":"Wait.","TWN":"等等。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"건물 안에는 고치가 없잖아?","JPN":"建物の中に繭がない？","ENG":"There's no cocoon inside the building.","TWN":"建築裡沒有繭？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨, 로널드 박사님이 보낸 좌표 좀 다시 확인해줄래요?","JPN":"シノンさん、ロナルド博士から送られてきた座標をもう一度確認してもらえますか？","ENG":"Shiyoung, could you recheck the coordinates Dr. Ronald sent us?","TWN":"時雨，能重新確認下博士發來的座標嗎？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"설마 그때 고치가 보이지 않았던 이유는 네피림이 고치에서 깨어난 게 아니라…….","JPN":"まさか、あの時繭が見えなかったのは、ネフィリムが繭から孵化したからじゃなくて……","ENG":"Then the reason we couldn't find the cocoon at that time was not because it hatched, but...","TWN":"那個時候沒有發現諾菲力的繭，難道不是因為孵化了……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L50_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어, 어쨌든 이걸로 확실해졌어!","JPN":"と、とにかくこれではっきりしたぞ！","ENG":"A-anyway, this explains everything!","TWN":"總，總之，可以確定一點！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아포리아의 목적은 전 세계에 각지에 있는 네피림의 고치야!","JPN":"アポリアの目的は世界各地にあるネフィリムの繭だ！","ENG":"Aporia's objective is the Nephil cocoons spread throughout the world!","TWN":"阿波利亞的目的是遍佈於世界各地的諾菲力繭！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"동족의 핵을 흡수해서! 더 상위종으로 올라가려는 게 틀림없다고!","JPN":"同族の核を吸収し、より上位種になろうとしているに違いない！","ENG":"It's cannibalizing to become a high-category C.O.!","TWN":"吸收同族的核心！然後進化成為更加高階的物種！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};